var e=[{id:`L2_1`,type:`dialog`,speaker:`SERAPEL_QLIPHOTH_NULL_NULL`,text:{KOREA:`하아…… 하아……`,JPN:`はぁ……はぁ……`,ENG:`*Pant*... *Pant*...`,TWN:`哈啊……哈啊……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERAPEL_QLIPHOTH_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_NULL`,text:{KOREA:`벌써 끝내려고? 마왕이라면 적어도 격은 갖추지 그러느냐?`,JPN:`もう終わりか？　魔王を名乗るなら、せめて品格くらい備えたらどうじゃ？`,ENG:`Done already? Have you no dignity in your title of Demon Lord?`,TWN:`這麼快就想結束了？身為魔王的尊嚴呢？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_NULL`,text:{KOREA:`저 녀석의 의도에 어울려 주는 건 내키지 않는다만, 얼치기 하나 훈계하는 셈이라면야 넘어가 줄까.`,JPN:`其方の計画の手助けとなるのは気が進まないが、どっちつかずの態度を戒めるつもりなら見逃してやろう。`,ENG:`I'm not really happy about playing along in her game, but I shall gladly take the opportunity to discipline an idiot.`,TWN:`雖然被你利用讓我有些不愉快，但能夠教訓教訓不知天高地厚的後輩，還是蠻開心的。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`네. 모쪼록 천천히 즐기시죠.`,JPN:`はい。ぜひごゆっくりお楽みください。`,ENG:`Thank you. Please, savor your time.`,TWN:`感謝，請隨意。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`저희도 각오는 하고 왔으니까요. 동귀어진이라고 하죠?`,JPN:`我々も覚悟はしていますから。死なば諸共といいましょうか？`,ENG:`We did come prepared, after all. There will be no victors in this battle.`,TWN:`我們也做好心理準備了。應該叫同歸於盡吧？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SERAPEL_QLIPHOTH_NULL_NULL`,text:{KOREA:`탐식자…… 네가……!`,JPN:`貪食者……あなた……！`,ENG:`Devourer... You...!`,TWN:`貪食者……你……！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERAPEL_QLIPHOTH_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};